import{_ as t,o as e,c as a,a2 as u}from"./chunks/framework.Crpw6aS5.js";const b=JSON.parse('{"title":"逆向思维","description":"","frontmatter":{},"headers":[],"relativePath":"05_quotes/by-theme/逆向思维.md","filePath":"05_quotes/by-theme/逆向思维.md"}'),q={name:"05_quotes/by-theme/逆向思维.md"};function r(l,o,c,p,_,s){return e(),a("div",null,[...o[0]||(o[0]=[u('<h1 id="逆向思维" tabindex="-1">逆向思维 <a class="header-anchor" href="#逆向思维" aria-label="Permalink to &quot;逆向思维&quot;">​</a></h1><blockquote><p>&quot;在别人贪婪时恐惧，在别人恐惧时贪婪。&quot;——巴菲特</p></blockquote><p>逆向思维是巴菲特从老师格雷厄姆那里继承并在实践中发扬的投资哲学。</p><hr><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><blockquote><p>&quot;在别人恐惧时贪婪，在别人贪婪时恐惧。这句话说起来容易，做起来需要勇气。&quot;</p></blockquote><blockquote><p>&quot;当潮水退去，才知道谁在裸泳。经济危机是检验企业真正质量的时刻。&quot;</p></blockquote><blockquote><p>&quot;我们希望拥有持久的竞争优势。但当整个市场都在恐慌性抛售时，即使是最好的公司也会被错杀——这正是买入的好时机。&quot;</p></blockquote><blockquote><p>&quot;查理和我不关心下个季度或明年的收益。我们关心的是，企业十年后会怎样。市场的短期波动给我们提供了买入机会。&quot;</p></blockquote><blockquote><p>&quot;在投资中，逆向思维意味着与大众保持距离。这需要自信，也需要耐心。&quot;</p></blockquote><blockquote><p>&quot;1969年，当所有人都想买入时，我们清算了合伙企业。我们不追求完美时机，但我们知道什么时候价格太高了。&quot;</p></blockquote><hr><h2 id="出处年份" tabindex="-1">出处年份 <a class="header-anchor" href="#出处年份" aria-label="Permalink to &quot;出处年份&quot;">​</a></h2><p>1969年 · 1974年 · 1986年 · 1996年 · 2008年 · 2020年</p>',14)])])}const i=t(q,[["render",r]]);export{b as __pageData,i as default};
